import { IMessageComposer } from '@nitrots/nitro-renderer';

export class GetCorporationRanksComposer implements IMessageComposer<any[]> {
    private _data: any[];

    constructor(corporationId: number) {
        this._data = [corporationId];
        console.log('[📤] GetCorporationRanksComposer:', this._data);
    }

    public getMessageArray(): any[] {
        return this._data;
    }
    public dispose(): void {
        /* no-op */
    }
}
